1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1], [0, 1],
6	  [1, -1], [1, 0], [1, 1],
7	];
8	
9	const MIN_SURVIVAL_NEIGHBORS = 2;
10	const BIRTH_NEIGHBORS = 3;
11	
12	function sameCell([ax, ay]: Cell, [bx, by]: Cell): boolean {
13	  return ax === bx && ay === by;
14	}
15	
16	function neighborsOf([x, y]: Cell): Cell[] {
17	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
18	}
19	
20	function survivesNextGeneration(cell: Cell, cells: Cell[]): boolean {
21	  const isAlive = cells.some((c) => sameCell(c, cell));
22	  const liveNeighbors = neighborsOf(cell).filter((n) =>
23	    cells.some((c) => sameCell(c, n)),
24	  ).length;
25	
26	  return isAlive
27	    ? liveNeighbors >= MIN_SURVIVAL_NEIGHBORS &&
28	        liveNeighbors <= BIRTH_NEIGHBORS
29	    : liveNeighbors === BIRTH_NEIGHBORS;
30	}
31	
32	export function nextGeneration(cells: Cell[]): Cell[] {
33	  const candidates = cells.flatMap(neighborsOf).concat(cells);
34	
35	  const next: Cell[] = [];
36	  for (const candidate of candidates) {
37	    const alreadyAdded = next.some((c) => sameCell(c, candidate));
38	    if (!alreadyAdded && survivesNextGeneration(candidate, cells)) {
39	      next.push(candidate);
40	    }
41	  }
42	  return next;
43	}
