export function nextGeneration(cells: Cell[]): Cell[] {
  const candidates = cells.flatMap(neighborsOf).concat(cells);

  const next: Cell[] = [];
  for (const candidate of candidates) {
    const alreadyAdded = next.some((c) => sameCell(c, candidate));
    if (!alreadyAdded && survivesNextGeneration(candidate, cells)) {
      next.push(candidate);
    }
  }
  return next;
}

